diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 0633388cd411..0cb8d488fa8c 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -2879,7 +2879,64 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
   if (Instruction *I = canonicalizeScalarSelectOfVecs(SI, *this))
     return I;

-  // If the type of select is not an integer type or if the condition and
+  // select (select t1, t2, false), c, (select t1, a, b)
+  //   -> select t1, (select t2, c, a), b
+  // This handles: (t1 && t2) ? c : (t1 ? a : b) -> t1 ? (t2 ? c : a) : b
+  if (auto *CondSI = dyn_cast<SelectInst>(CondVal)) {
+    Value *CondSIFalse = CondSI->getFalseValue();
+    if (isa<ConstantInt>(CondSIFalse) && cast<ConstantInt>(CondSIFalse)->isZero() &&
+        CondSI->hasOneUse()) {
+      if (auto *FVSI = dyn_cast<SelectInst>(FalseVal)) {
+        Value *CondSICond = CondSI->getCondition();
+        if (FVSI->getCondition() == CondSICond && FVSI->hasOneUse()) {
+          Value *T1 = CondSICond;
+          Value *T2 = CondSI->getTrueValue();
+          Value *A = FVSI->getTrueValue();
+          Value *B = FVSI->getFalseValue();
+          Value *NewS1 = Builder.CreateSelect(T2, TrueVal, A, "folded_sel");
+          return SelectInst::Create(T1, NewS1, B);
+        }
+      }
+    }
+
+    // select (select t1, true, t2), (select t1, a, b), c
+    //   -> select t1, a, (select t2, b, c)
+    // This handles: (t1 || t2) ? (t1 ? a : b) : c -> t1 ? a : (t2 ? b : c)
+    Value *CondSITrue = CondSI->getTrueValue();
+    if (isa<ConstantInt>(CondSITrue) && cast<ConstantInt>(CondSITrue)->isOne() &&
+        CondSI->hasOneUse()) {
+      if (auto *TVSI = dyn_cast<SelectInst>(TrueVal)) {
+        Value *CondSICond = CondSI->getCondition();
+        if (TVSI->getCondition() == CondSICond && TVSI->hasOneUse()) {
+          Value *T1 = CondSICond;
+          Value *T2 = CondSI->getFalseValue();
+          Value *A = TVSI->getTrueValue();
+          Value *B = TVSI->getFalseValue();
+          Value *NewS1 = Builder.CreateSelect(T2, B, FalseVal, "folded_sel");
+          return SelectInst::Create(T1, A, NewS1);
+        }
+      }
+    }
+  }
+
+  // select (t1 && t2), c, (select t1, a, b) -> select t1, (select t2, c, a), b
+  // Handles case where inner select was folded to 'and' by foldSelectOfBools
+  if (auto *And = dyn_cast<BinaryOperator>(CondVal)) {
+    if (And->getOpcode() == Instruction::And) {
+      if (auto *FVSI = dyn_cast<SelectInst>(FalseVal)) {
+        Value *AndOp0 = And->getOperand(0);
+        if (FVSI->getCondition() == AndOp0 && FVSI->hasOneUse()) {
+          Value *T1 = AndOp0;
+          Value *T2 = And->getOperand(1);
+          Value *A = FVSI->getTrueValue();
+          Value *B = FVSI->getFalseValue();
+          Value *NewS1 = Builder.CreateSelect(T2, TrueVal, A, "folded_sel");
+          return SelectInst::Create(T1, NewS1, B);
+        }
+      }
+    }
+  }
+
   // the selection type are not both scalar nor both vector types, there is no
   // point in attempting to match these patterns.
   Type *CondType = CondVal->getType();

